+    ret = rcl_arguments_get_log_levels(&local_arguments, &log_levels); \
+    EXPECT_EQ(RCL_RET_OK, ret) << rcl_get_error_string().str; \
+    OSRF_TESTING_TOOLS_CPP_SCOPE_EXIT( \
