+  // Copy type sources
+  for (size_t i = 0; i < runtime_type_sources->size; ++i) {
+    // type_name
+    if (!rosidl_runtime_c__String__copy(
+        &(runtime_type_sources->data[i].type_name), &(out->data[i].type_name)))
+    {
+      goto fail;
