+static bool string_in_array(rcutils_string_array_t * array, const char * pattern)
+{
+  for (size_t i = 0; i < array->size; ++i) {
+    if (strcmp(array->data[i], pattern) == 0) {
+      return true;
+    }
+  }
+  return false;
+}
