+/* Test init and fini functions. */
+TEST_F(
+  CLASSNAME(TestGetTypeDescSrvFixture, RMW_IMPLEMENTATION),
+  test_service_init_and_fini_functions) {
+  EXPECT_TRUE(
+    service_exists(
