+bool
+rcl_action_client_is_valid(const rcl_action_client_t * action_client)
+{
+  RCL_CHECK_ARGUMENT_FOR_NULL(action_client, false);
+  RCL_CHECK_FOR_NULL_WITH_MSG(
+    action_client->impl,
+    "action client's implementation is invalid",
+    return false);
+  return true;
+}
