+
+  rcl_lifecycle_state_machine_t state_machine2 =
+    rcl_lifecycle_get_zero_initialized_state_machine();
+  rcl_lifecycle_init_default_state_machine(&state_machine2);
+
+  rcl_lifecycle_state_machine_t state_machine3 =
+    rcl_lifecycle_get_zero_initialized_state_machine();
