+  if (time_source->type != RCL_ROS_TIME) {
+    RCL_SET_ERROR_MSG("time_source not of type RCL_ROS_TIME");
+    return RCL_RET_ERROR;
+  }
+  free((rcl_ros_time_source_storage_t *)time_source->data);
+  return RCL_RET_OK;
+}
